<template>
  <div class="hello">
    <div v-if="screenWidth <= 750">
      <el-row>
        <el-col :span="5">
          <el-row>
            星级
          </el-row>
          <el-row v-for="(level,index) in levels" :key="index">
            <el-tag size="large" :type="colorTypes[index]">
              {{ level }}={{ Math.pow(3, 4 - index) }}
            </el-tag>
          </el-row>
        </el-col>
        <el-col :span="8">
          <el-row>
            需求 <br>
            ({{ needsSum }})
          </el-row>
          <el-row v-for="(level,index) in levels" :key="index">
            <el-input-number
                style="width:100px" v-model="needs[index]" :min="0"
                @change="onChange"
            />
          </el-row>
        </el-col>
        <el-col :span="8">
          <el-row>
            拥有 <br>
            ({{ ownsSum }})
          </el-row>
          <el-row v-for="(level,index) in levels" :key="index">
            <el-input-number
                style="width:100px" v-model="owns[index]" :min="0"
                @change="onChange"
            />
          </el-row>
        </el-col>
        <el-col :span="3">
          <el-row>
            相差 <br>
            ({{ diffsSum }})
          </el-row>
          <el-row v-for="(level,index) in levels" :key="index">
            <el-tag :type="diffs[index]<=0?'success':diffs[index]<3?'':'danger'">
              {{ diffs[index] }}
            </el-tag>
          </el-row>
        </el-col>
      </el-row>
      <el-row align="middle">
        <el-col :span="5">
          <el-button @click="Object.assign(this.$data, this.$options.data.call(this))">重置</el-button>
        </el-col>
        <el-col :span="17" :offset="1">
          <el-progress
              :text-inside="true"
              :stroke-width="24"
              :percentage="progress"
          />
        </el-col>
      </el-row>
    </div>
    <div v-else>
      <el-row>
        <el-col :span="4">
          星级
        </el-col>
        <el-col :span="4" v-for="(level,index) in levels" :key="index">
          <el-tag size="large" :type="colorTypes[index]">
            {{ `${level}色【${5 - index}】= ${Math.pow(3, 4 - index)}` }}
          </el-tag>
        </el-col>
      </el-row>
      <el-row>
        <el-col :span="4">
          需求({{ needsSum }})
        </el-col>
        <el-col :span="4" v-for="(level,index) in levels" :key="index">
          <el-input-number
              style="width:100px" v-model="needs[index]" :min="0"
              @change="onChange"
          />
        </el-col>
      </el-row>
      <el-row>
        <el-col :span="4">
          拥有({{ ownsSum }})
        </el-col>
        <el-col :span="4" v-for="(level,index) in levels" :key="index">
          <el-input-number
              style="width:100px" v-model="owns[index]" :min="0"
              @change="onChange"
          />
        </el-col>
      </el-row>
      <el-row>
        <el-col :span="4">
          相差({{ diffsSum }})
        </el-col>
        <el-col :span="4" v-for="(level,index) in levels" :key="index">
          <el-tag :type="diffs[index]<=0?'success':diffs[index]<3?'':'danger'">
            {{ diffs[index] }}
          </el-tag>
        </el-col>
      </el-row>
      <el-row>
        <el-col :span="4">
          <el-button @click="Object.assign(this.$data, this.$options.data.call(this))">重置</el-button>
        </el-col>
        <el-col :span="18" :offset="1">
          <el-progress
              :text-inside="true"
              :stroke-width="24"
              :percentage="progress"
          />
        </el-col>
      </el-row>
    </div>
  </div>
</template>

<script>
const throttle = function (type, name, obj) {
  obj = obj || window
  var running = false
  var func = function () {
    if (running) { return }
    running = true
    requestAnimationFrame(function () {
      obj.dispatchEvent(new CustomEvent(name))
      running = false
    })
  }
  obj.addEventListener(type, func)
}

export default {
  name: 'MaterialCounter',
  props: {
    msg: String,
  },
  data () {
    return {
      // const
      levels: ['金', '紫', '蓝', '绿', '灰'],
      colorTypes: ['warning', 'danger', '', 'success', 'info'],

      // var const
      screenWidth: screen.width,

      // var
      needs: [0, 0, 0, 0, 0],
      needsSum: 0,
      owns: [0, 0, 0, 0, 0],
      ownsSum: 0,
      diffs: [0, 0, 0, 0, 0],
      diffsSum: 0,
      progress: 0,
    }
  },
  created () {
    const that = this

    throttle('resize', 'optimizedResize')
    window.addEventListener('optimizedResize', function () {
      console.log('Resource conscious resize callback!', screen.width)
      that.screenWidth = screen.width
    })

    try {
      this.needs = localStorage.getItem('needs') ?
          JSON.parse(localStorage.getItem('needs')) : this.needs
      this.owns = localStorage.getItem('owns') ?
          JSON.parse(localStorage.getItem('owns')) : this.owns
    } catch (e) {
      console.log(e)
    }
    this.onChange()
  },
  methods: {
    onChange () {
      localStorage.setItem('needs', JSON.stringify(this.needs))
      localStorage.setItem('owns', JSON.stringify(this.owns))

      let firstNeed = this.needs.findIndex(v => v > 0)

      let calcSum = (sum, value, index) => sum * 3 + (index >= firstNeed ? value : 0)
      this.needsSum = this.needs.reduce(calcSum, 0)
      this.ownsSum = this.owns.reduce(calcSum, 0)
      this.diffsSum = this.needsSum - this.ownsSum

      this.progress = this.needsSum > 0 ? this.ownsSum / this.needsSum * 100 : 0
      this.progress = this.progress > 100 ? 100 : this.progress < 0 ? 0 :
          this.progress.toFixed(2)

      this.diffs = this.levels.map((_, index) =>
          index < firstNeed ? 0 :
              index === firstNeed ?
                  (this.diffsSum / Math.pow(3, 4 - index)) :
                  (this.diffsSum / Math.pow(3, 4 - index)) % 3,
      ).map(Math.floor)
    },
  },
}
</script>

